  { name: "hour" as const, min: 0, max: 23 },
  { name: "dayOfMonth" as const, min: 1, max: 31 },
  { name: "month" as const, min: 1, max: 12 },
  { name: "dayOfWeek" as const, min: 0, max: 6 },
] as const;

type FieldName = (typeof FIELD_CONFIG)[number]["name"];

function parseIntStrict(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid numeric value "${raw}" in ${context}`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Non-finite numeric value "${raw}" in ${context}`);
  }
  return n;
}

