  if (step <= 0) {
    throw new Error(`Step must be a positive integer in field "${fieldName}", got ${step}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in field "${fieldName}"`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

