  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const base = segment.slice(0, slashIdx);
    const stepRaw = segment.slice(slashIdx + 1);

    if (!stepRaw) {
      throw new Error(`Missing step value after "/" in field "${fieldName}": "${segment}"`);
    }

    const step = parseIntStrict(stepRaw, `"${fieldName}" step`);
    if (step === 0) {
      throw new Error(`Step value must not be zero in field "${fieldName}"`);
    }

    if (base === "*") {
      return buildRange(min, max, step, fieldName);
    }

    if (base.includes("-")) {
      const dashParts = base.split("-");
      if (dashParts.length !== 2 || !dashParts[0] || !dashParts[1]) {
        throw new Error(`Malformed range "${base}" in field "${fieldName}"`);
      }
      const rangeStart = parseIntStrict(dashParts[0], `"${fieldName}" range start`);
      const rangeEnd = parseIntStrict(dashParts[1], `"${fieldName}" range end`);
      assertInRange(rangeStart, min, max, fieldName);
      assertInRange(rangeEnd, min, max, fieldName);
      return buildRange(rangeStart, rangeEnd, step, fieldName);
    }

    throw new Error(
      `Invalid step expression "${segment}" in field "${fieldName}": base must be "*" or a range`
    );
  }

  // Wildcard: *
  if (segment === "*") {
    return buildRange(min, max, 1, fieldName);
  }

  // Range: A-B
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2 || !dashParts[0] || !dashParts[1]) {
      throw new Error(`Malformed range "${segment}" in field "${fieldName}"`);
    }
    const rangeStart = parseIntStrict(dashParts[0], `"${fieldName}" range start`);
    const rangeEnd = parseIntStrict(dashParts[1], `"${fieldName}" range end`);
    assertInRange(rangeStart, min, max, fieldName);
    assertInRange(rangeEnd, min, max, fieldName);
    return buildRange(rangeStart, rangeEnd, 1, fieldName);
  }

  // Single value
  const value = parseIntStrict(segment, `"${fieldName}" value`);
  assertInRange(value, min, max, fieldName);
  return [value];
