  if (segments.some((s) => !s)) {
    throw new Error(
      `Trailing, leading, or consecutive commas in field "${fieldName}": "${token}"`
    );
  }

  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max, fieldName);
    for (const v of parsed) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (!trimmed) {
    throw new Error("Cron expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${tokens.length}: "${expression}"`
    );
  }

  const result = {} as Record<FieldName, number[]>;

  for (let i = 0; i < FIELD_CONFIG.length; i++) {
    const { name, min, max } = FIELD_CONFIG[i];
